240	pub fn braces(global: *jsc.JSGlobalObject, brace_str: bun.String, opts: gen.BracesOptions) bun.JSError!jsc.JSValue {
241	    const brace_slice = brace_str.toUTF8(bun.default_allocator);
242	    defer brace_slice.deinit();
243	
244	    var arena = std.heap.ArenaAllocator.init(bun.default_allocator);
245	    defer arena.deinit();
246	
247	    var lexer_output = lexer_output: {
248	        if (bun.strings.isAllASCII(brace_slice.slice())) {
249	            break :lexer_output Braces.Lexer.tokenize(arena.allocator(), brace_slice.slice()) catch |err| {
250	                return global.throwError(err, "failed to tokenize braces");
251	            };
252	        }
253	
254	        break :lexer_output Braces.NewLexer(.wtf8).tokenize(arena.allocator(), brace_slice.slice()) catch |err| {
255	            return global.throwError(err, "failed to tokenize braces");
256	        };
257	    };
258	
259	    const expansion_count = Braces.calculateExpandedAmount(lexer_output.tokens.items[0..]);
260	
261	    if (opts.tokenize) {
262	        const str = bun.handleOom(std.fmt.allocPrint(global.bunVM().allocator, "{f}", .{std.json.fmt(lexer_output.tokens.items[0..], .{})}));
263	        defer global.bunVM().allocator.free(str);
264	        var bun_str = bun.String.fromBytes(str);
265	        return bun_str.toJS(global);
266	    }
267	    if (opts.parse) {
268	        var parser = Braces.Parser.init(lexer_output.tokens.items[0..], arena.allocator());
269	        const ast_node = parser.parse() catch |err| {
270	            return global.throwError(err, "failed to parse braces");
271	        };
272	        const str = bun.handleOom(std.fmt.allocPrint(global.bunVM().allocator, "{f}", .{std.json.fmt(ast_node, .{})}));
273	        defer global.bunVM().allocator.free(str);
274	        var bun_str = bun.String.fromBytes(str);
275	        return bun_str.toJS(global);
276	    }
277	
278	    if (expansion_count == 0) {
279	        return bun.String.toJSArray(global, &.{brace_str});
280	    }
281	
282	    var expanded_strings = try arena.allocator().alloc(std.array_list.Managed(u8), expansion_count);
283	
284	    for (0..expansion_count) |i| {
285	        expanded_strings[i] = std.array_list.Managed(u8).init(arena.allocator());
286	    }
287	
288	    Braces.expand(
289	        arena.allocator(),
290	        lexer_output.tokens.items[0..],
291	        expanded_strings,
292	        lexer_output.contains_nested,
293	    ) catch |err| switch (err) {
294	        error.OutOfMemory => |e| return e,
295	        error.UnexpectedToken => return global.throwPretty("Unexpected token while expanding braces", .{}),
296	    };
297	
298	    var out_strings = try arena.allocator().alloc(bun.String, expansion_count);
299	    for (0..expansion_count) |i| {
300	        out_strings[i] = bun.String.fromBytes(expanded_strings[i].items[0..]);
301	    }
302	
303	    return bun.String.toJSArray(global, out_strings[0..]);
304	}
