95	const Stringifier = struct {
96	    stack_check: bun.StackCheck,
97	    builder: wtf.StringBuilder,
98	    indent: usize,
99	    space: Space,
100	    visiting: std.AutoHashMapUnmanaged(JSValue, void),
101	    allocator: std.mem.Allocator,
102	
103	    const StringifyError = bun.JSError || bun.StackOverflow;
104	
105	    const Space = union(enum) {
106	        minified,
107	        number: u32,
108	        str: bun.String,
109	
110	        pub fn init(global: *jsc.JSGlobalObject, space_value: JSValue) bun.JSError!Space {
111	            const space = try space_value.unwrapBoxedPrimitive(global);
112	            if (space.isNumber()) {
113	                // Clamp on the float to match the spec's min(10, ToIntegerOrInfinity(space)).
114	                // toInt32() wraps large values and Infinity to 0, which is wrong.
115	                const num_f = space.asNumber();
116	                if (!(num_f >= 1)) return .minified; // handles NaN, -Infinity, 0, negatives
117	                return .{ .number = if (num_f > 10) 10 else @intFromFloat(num_f) };
118	            }
119	            if (space.isString()) {
120	                const str = try space.toBunString(global);
121	                if (str.length() == 0) {
122	                    str.deref();
123	                    return .minified;
124	                }
125	                return .{ .str = str };
126	            }
127	            return .minified;
128	        }
129	
130	        pub fn deinit(this: *const Space) void {
131	            switch (this.*) {
132	                .str => |str| str.deref(),
133	                .minified, .number => {},
134	            }
135	        }
136	    };
137	
138	    pub fn init(global: *jsc.JSGlobalObject, space_value: JSValue) bun.JSError!Stringifier {
139	        return .{
140	            .stack_check = .init(),
141	            .builder = .init(),
142	            .indent = 0,
143	            .space = try Space.init(global, space_value),
144	            .visiting = .empty,
145	            .allocator = bun.default_allocator,
146	        };
147	    }
148	
149	    pub fn deinit(this: *Stringifier) void {
150	        this.builder.deinit();
151	        this.space.deinit();
152	        this.visiting.deinit(this.allocator);
153	    }
