pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();
    const input = input_slice.slice();

    const root = JSValue.createEmptyObject(globalThis, 4);
    var current_section: JSValue = .js_undefined;

    var line_num: usize = 0;
    var line_iter = std.mem.splitScalar(u8, input, '\n');
    while (line_iter.next()) |raw_line| {
        line_num += 1;
        // Handle \r\n line endings
        const without_cr: []const u8 = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
            raw_line[0 .. raw_line.len - 1]
        else
            raw_line;
        const line = std.mem.trim(u8, without_cr, " \t");

        // Skip empty lines and comment lines (starting with ; or #)
        if (line.len == 0 or line[0] == ';' or line[0] == '#') continue;

        // Section header: [section name]
        if (line[0] == '[') {
            if (line[line.len - 1] != ']') {
                return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                    "INI parse error on line {d}: missing closing ']' in section header",
                    .{line_num},
                ));
            }
            const section_name = std.mem.trim(u8, line[1 .. line.len - 1], " \t");
            if (section_name.len == 0) {
                return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                    "INI parse error on line {d}: empty section name",
                    .{line_num},
                ));
            }
            const section_obj = JSValue.createEmptyObject(globalThis, 4);
            var section_key = bun.String.borrowUTF8(section_name);
            defer section_key.deref();
            try root.putMayBeIndex(globalThis, &section_key, section_obj);
            current_section = section_obj;
            continue;
        }

        // Key=value pair
        const eq_idx = std.mem.indexOf(u8, line, "=") orelse {
            return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                "INI parse error on line {d}: expected '=' in key-value pair",
                .{line_num},
            ));
        };

        const key = std.mem.trim(u8, line[0..eq_idx], " \t");
        const value = std.mem.trim(u8, line[eq_idx + 1 ..], " \t");

        if (key.len == 0) {
            return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                "INI parse error on line {d}: empty key",
                .{line_num},
            ));
        }

        var key_str = bun.String.borrowUTF8(key);
        defer key_str.deref();
        var value_bun = bun.String.borrowUTF8(value);
        defer value_bun.deref();
        const value_js = value_bun.toJS(globalThis);

        if (!current_section.isUndefined()) {
            try current_section.putMayBeIndex(globalThis, &key_str, value_js);
        } else {
            try root.putMayBeIndex(globalThis, &key_str, value_js);
        }
    }

    return root;
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }
    if (!input_value.isObject()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    // First pass: flat key=value pairs (skip nested objects which become sections)
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try input_value.toObject(globalThis),
        );
        defer iter.deinit();
        while (try iter.next()) |prop_name| {
            const val = iter.value;
            if (val.isUndefined() or val.isSymbol() or val.isFunction()) continue;
            // Skip nested objects — they become [section] blocks in the second pass
            if (val.isObject() and !val.isArray()) continue;
            const val_str = try val.toBunString(globalThis);
            defer val_str.deref();
            builder.append(.string, prop_name);
            builder.append(.latin1, " = ");
            builder.append(.string, val_str);
            builder.append(.lchar, '\n');
        }
    }

    // Second pass: object values become [section] blocks
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try input_value.toObject(globalThis),
        );
        defer iter.deinit();
        while (try iter.next()) |prop_name| {
            const val = iter.value;
            if (!val.isObject() or val.isArray() or val.isFunction()) continue;

            builder.append(.lchar, '[');
            builder.append(.string, prop_name);
            builder.append(.latin1, "]\n");

            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                globalThis,
                try val.toObject(globalThis),
            );
            defer section_iter.deinit();
            while (try section_iter.next()) |key| {
                const section_val = section_iter.value;
                if (section_val.isUndefined() or section_val.isSymbol() or section_val.isFunction()) continue;
                if (section_val.isObject() and !section_val.isArray()) {
                    return globalThis.throw("INI.stringify does not support deeply nested objects", .{});
                }
                const section_val_str = try section_val.toBunString(globalThis);
                defer section_val_str.deref();
                builder.append(.string, key);
                builder.append(.latin1, " = ");
                builder.append(.string, section_val_str);
                builder.append(.lchar, '\n');
            }
        }
    }

    return builder.toString(globalThis);
}

